/** Absolute epoch (ms) of a sample. */
export function sampleTime(sample: TrackSample): number {
  return TIMELINE_BASE + sample.o * 1000;
}

export function trackStart(track: GpsTrack): number {
  return sampleTime(track.samples[0]);
}

export function trackEnd(track: GpsTrack): number {
  return sampleTime(track.samples[track.samples.length - 1]);
}

/** Earliest start / latest end across every track — the clock's full extent. */
export const playbackBounds = {
  start: Math.min(...gpsTracks.map(trackStart)),
  end: Math.max(...gpsTracks.map(trackEnd)),
};

const toRad = (deg: number) => (deg * Math.PI) / 180;
const toDeg = (rad: number) => (rad * 180) / Math.PI;

/** Initial bearing from a → b, in degrees clockwise from north [0, 360). */
export function bearingBetween(
  a: { lng: number; lat: number },
  b: { lng: number; lat: number },
): number {
  const lat1 = toRad(a.lat);
  const lat2 = toRad(b.lat);
  const dLng = toRad(b.lng - a.lng);
  const y = Math.sin(dLng) * Math.cos(lat2);
  const x =
    Math.cos(lat1) * Math.sin(lat2) -
    Math.sin(lat1) * Math.cos(lat2) * Math.cos(dLng);
  return (toDeg(Math.atan2(y, x)) + 360) % 360;
}

export type TrackPosition = {
  lng: number;
  lat: number;
  /** Heading in degrees, for orienting the marker. */
  bearing: number;
  /** Whether the cursor sits within this track's own time span. */
  active: boolean;
};

/**
 * Position of a track at clock time `t` (epoch ms). The point is linearly
 * interpolated between surrounding GPS fixes and clamped to the track's span,
 * mirroring LeafletPlayback's per-tick interpolation.
 */
export function interpolatePosition(track: GpsTrack, t: number): TrackPosition {
  const samples = track.samples;
  const start = trackStart(track);
  const end = trackEnd(track);
  const active = t >= start && t <= end;
  const clamped = Math.max(start, Math.min(end, t));

  let i = 0;
  while (
    i < samples.length - 1 &&
    sampleTime(samples[i + 1]) <= clamped
  ) {
    i += 1;
  }

  const curr = samples[i];
  const next = samples[Math.min(i + 1, samples.length - 1)];
  const span = sampleTime(next) - sampleTime(curr);
  const ratio = span > 0 ? (clamped - sampleTime(curr)) / span : 0;

  const lng = curr.lng + (next.lng - curr.lng) * ratio;
  const lat = curr.lat + (next.lat - curr.lat) * ratio;
  const bearing =
    curr === next ? bearingBetween(samples[Math.max(0, i - 1)], curr) : bearingBetween(curr, next);

  return { lng, lat, bearing, active };
}

/** Full polyline for a track. */
export function fullPath(track: GpsTrack): [number, number][] {
  return track.samples.map((s) => [s.lng, s.lat]);
}

/** The portion of a track already travelled by clock time `t`. */
export function traveledPath(track: GpsTrack, t: number): [number, number][] {
  const coords: [number, number][] = [];
  for (const sample of track.samples) {
    if (sampleTime(sample) <= t) coords.push([sample.lng, sample.lat]);
    else break;
  }
  const head = interpolatePosition(track, t);
  coords.push([head.lng, head.lat]);
  return coords;
}

const WEEKDAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
const MONTHS = [
  "Jan", "Feb", "Mar", "Apr", "May", "Jun",
  "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
];

const pad2 = (n: number) => String(n).padStart(2, "0");

/** Clock time formatted in UTC, e.g. "17:12" or "17:12:18". */
export function formatClock(t: number, withSeconds = false): string {
  const d = new Date(t);
  const base = `${pad2(d.getUTCHours())}:${pad2(d.getUTCMinutes())}`;
  return withSeconds ? `${base}:${pad2(d.getUTCSeconds())}` : base;
}

/** Calendar day formatted in UTC, e.g. "Tue 28 May". */
export function formatDay(t: number): string {
  const d = new Date(t);
  return `${WEEKDAYS[d.getUTCDay()]} ${d.getUTCDate()} ${MONTHS[d.getUTCMonth()]}`;
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";

import { cn } from "@/lib/utils";
import { formatClock, formatDay, sampleTime, type GpsTrack } from "../data";

type Bounds = { start: number; end: number };

type PlaybackTimelineProps = {
  tracks: GpsTrack[];
  /** Full extent of the data (epoch ms). */
  bounds: Bounds;
  /** Current cursor position (epoch ms). */
  currentTime: number;
  /** Seek the cursor to an absolute time. */
  onSeek: (time: number) => void;
  /** Called when the user grabs the cursor (used to pause during a scrub). */
  onScrubStart?: () => void;
  /** Called when the user releases the cursor. */
  onScrubEnd?: () => void;
  className?: string;
};

// Geometry of the timeline graph, in px.
const GRAPH_HEIGHT = 104;
const AXIS_Y = 64;
const ROW_TOP = 9;
const ROW_HEIGHT = 22;
const ROW_GAP = 4;

// Candidate axis steps (ms), from 1s up to 1 day — the timeline snaps grid
// lines to the smallest of these that keeps labels from crowding.
const TICK_STEPS = [
  1, 2, 5, 10, 15, 30, 60, 120, 300, 600, 900, 1800, 3600, 7200, 10800, 21600,
  43200, 86400,
].map((s) => s * 1000);

type WindowConfig = {
  outerMin: number;
  outerMax: number;
  minSpan: number;
  maxSpan: number;
};

const clamp = (value: number, min: number, max: number) =>
  Math.max(min, Math.min(max, value));

function clampWindow(cfg: WindowConfig, start: number, end: number): Bounds {
  const span = clamp(end - start, cfg.minSpan, cfg.maxSpan);
  let nextStart = start;
  let nextEnd = start + span;
  if (nextStart < cfg.outerMin) {
    nextStart = cfg.outerMin;
    nextEnd = nextStart + span;
  }
  if (nextEnd > cfg.outerMax) {
    nextEnd = cfg.outerMax;
    nextStart = Math.max(cfg.outerMin, nextEnd - span);
  }
  return { start: nextStart, end: nextEnd };
}

function chooseStep(span: number, width: number): number {
  const targetTicks = Math.max(2, width / 90);
  const raw = span / targetTicks;
  return TICK_STEPS.find((step) => step >= raw) ?? TICK_STEPS[TICK_STEPS.length - 1];
}

function withAlpha(hex: string, alpha: number): string {
  const value = parseInt(hex.replace("#", ""), 16);
  const r = (value >> 16) & 255;
  const g = (value >> 8) & 255;
  const b = value & 255;
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}

type DragState =
  | { mode: "idle" }
  | {
      mode: "pan";
      startX: number;
      winStart: number;
      winEnd: number;
      moved: boolean;
    }
  | { mode: "cursor" };

export function PlaybackTimeline({
  tracks,
  bounds,
  currentTime,
  onSeek,
  onScrubStart,
  onScrubEnd,
  className,
}: PlaybackTimelineProps) {
  const graphRef = useRef<HTMLDivElement>(null);
  const [width, setWidth] = useState(0);

  const cfg = useMemo<WindowConfig>(() => {
    const dataSpan = bounds.end - bounds.start;
    const pad = dataSpan * 0.06;
    return {
      outerMin: bounds.start - pad * 2,
      outerMax: bounds.end + pad * 2,
      minSpan: Math.min(60_000, dataSpan),
      maxSpan: dataSpan + pad * 4,
    };
  }, [bounds]);

  const [win, setWin] = useState<Bounds>(() => {
    const pad = (bounds.end - bounds.start) * 0.06;
    return { start: bounds.start - pad, end: bounds.end + pad };
  });

  // Refs so the native (non-passive) wheel handler always sees fresh values.
  const winRef = useRef(win);
  const cfgRef = useRef(cfg);
  const dragRef = useRef<DragState>({ mode: "idle" });

  useEffect(() => {
    winRef.current = win;
    cfgRef.current = cfg;
  });

  const span = win.end - win.start;
  const timeToX = (t: number) => (width ? ((t - win.start) / span) * width : 0);

  // Measure the graph width.
  useEffect(() => {
    const el = graphRef.current;
    if (!el) return;
    const observer = new ResizeObserver(([entry]) => {
      setWidth(entry.contentRect.width);
    });
    observer.observe(el);
    setWidth(el.getBoundingClientRect().width);
    return () => observer.disconnect();
  }, []);

  // Wheel-to-zoom, anchored on the time under the pointer. Registered natively
  // so preventDefault works (React's onWheel is passive).
  useEffect(() => {
    const el = graphRef.current;
    if (!el) return;
    const handler = (event: WheelEvent) => {
      event.preventDefault();
      const rect = el.getBoundingClientRect();
      if (rect.width <= 0) return;
      const current = winRef.current;
      const config = cfgRef.current;
      const currentSpan = current.end - current.start;
      const ratio = (event.clientX - rect.left) / rect.width;
      const pivot = current.start + ratio * currentSpan;
      const factor = event.deltaY > 0 ? 1.18 : 1 / 1.18;
      const nextSpan = clamp(
        currentSpan * factor,
        config.minSpan,
        config.maxSpan,
      );
      setWin(
        clampWindow(config, pivot - ratio * nextSpan, pivot + (1 - ratio) * nextSpan),
      );
    };
    el.addEventListener("wheel", handler, { passive: false });
    return () => el.removeEventListener("wheel", handler);
  }, []);

  function handleBackgroundPointerDown(event: React.PointerEvent<HTMLDivElement>) {
    if (width <= 0) return;
    graphRef.current?.setPointerCapture(event.pointerId);
    dragRef.current = {
      mode: "pan",
      startX: event.clientX,
      winStart: win.start,
      winEnd: win.end,
      moved: false,
    };
  }

  function handleBackgroundPointerMove(event: React.PointerEvent<HTMLDivElement>) {
    const drag = dragRef.current;
    if (drag.mode !== "pan") return;
    const rect = graphRef.current?.getBoundingClientRect();
    if (!rect) return;
    const dx = event.clientX - drag.startX;
    if (Math.abs(dx) > 3) drag.moved = true;
    const dragSpan = drag.winEnd - drag.winStart;
    const dt = (dx / rect.width) * dragSpan;
    setWin(clampWindow(cfg, drag.winStart - dt, drag.winEnd - dt));
  }

  function handleBackgroundPointerUp(event: React.PointerEvent<HTMLDivElement>) {
    const drag = dragRef.current;
    const rect = graphRef.current?.getBoundingClientRect();
    if (drag.mode === "pan" && !drag.moved && rect) {
      const x = event.clientX - rect.left;
      onSeek(clamp(win.start + (x / rect.width) * span, bounds.start, bounds.end));
    }
    dragRef.current = { mode: "idle" };
    try {
      graphRef.current?.releasePointerCapture(event.pointerId);
    } catch {
      // ignore
    }
  }

  function handleCursorPointerDown(event: React.PointerEvent<HTMLDivElement>) {
    event.stopPropagation();
    event.currentTarget.setPointerCapture(event.pointerId);
    dragRef.current = { mode: "cursor" };
    onScrubStart?.();
  }

  function handleCursorPointerMove(event: React.PointerEvent<HTMLDivElement>) {
    if (dragRef.current.mode !== "cursor") return;
    event.stopPropagation();
    const rect = graphRef.current?.getBoundingClientRect();
    if (!rect) return;
    const x = event.clientX - rect.left;
    onSeek(clamp(win.start + (x / rect.width) * span, bounds.start, bounds.end));
  }

  function handleCursorPointerUp(event: React.PointerEvent<HTMLDivElement>) {
    if (dragRef.current.mode === "cursor") {
      event.stopPropagation();
      onScrubEnd?.();
    }
    dragRef.current = { mode: "idle" };
    try {
      event.currentTarget.releasePointerCapture(event.pointerId);
    } catch {
      // ignore
    }
  }

  const step = chooseStep(span, width || 1);
  const withSeconds = step < 60_000;
  const ticks: number[] = [];
  if (width > 0) {
    const first = Math.ceil(win.start / step) * step;
    for (let t = first; t <= win.end; t += step) ticks.push(t);
  }

  const cursorX = timeToX(currentTime);
  const cursorVisible = cursorX >= -8 && cursorX <= width + 8;

  return (
    <div className={cn("select-none", className)}>
      <div
        ref={graphRef}
        className="relative w-full cursor-grab touch-none overflow-hidden active:cursor-grabbing"
        style={{ height: GRAPH_HEIGHT }}
        onPointerDown={handleBackgroundPointerDown}
        onPointerMove={handleBackgroundPointerMove}
        onPointerUp={handleBackgroundPointerUp}
        onPointerCancel={handleBackgroundPointerUp}
      >
        {/* Vertical grid lines */}
        {ticks.map((t) => (
          <div
            key={`grid-${t}`}
            className="bg-border/60 absolute top-0 w-px"
            style={{ left: timeToX(t), height: AXIS_Y }}
          />
        ))}

        {/* Track range bars */}
        {tracks.map((track, index) => {
          const left = timeToX(sampleTime(track.samples[0]));
          const right = timeToX(
            sampleTime(track.samples[track.samples.length - 1]),
          );
          return (
            <div
              key={track.id}
              className="absolute flex items-center gap-1.5 overflow-hidden rounded-md border px-2 text-xs font-medium shadow-sm"
              style={{
                left,
                width: Math.max(0, right - left),
                top: ROW_TOP + index * (ROW_HEIGHT + ROW_GAP),
                height: ROW_HEIGHT,
                backgroundColor: withAlpha(track.color, 0.16),
                borderColor: withAlpha(track.color, 0.5),
              }}
            >
              <span
                className="size-2 shrink-0 rounded-full"
                style={{ backgroundColor: track.color }}
              />
              <span className="text-foreground/90 truncate">{track.label}</span>
            </div>
          );
        })}

        {/* Axis baseline */}
        <div
          className="bg-border absolute right-0 left-0 h-px"
          style={{ top: AXIS_Y }}
        />

        {/* Minor tick marks + labels */}
        {ticks.map((t) => (
          <div key={`label-${t}`}>
            <div
              className="bg-border absolute w-px"
              style={{ left: timeToX(t), top: AXIS_Y, height: 5 }}
            />
            <div
              className="text-muted-foreground absolute -translate-x-1/2 text-[11px] tabular-nums"
              style={{ left: timeToX(t), top: AXIS_Y + 8 }}
            >
              {formatClock(t, withSeconds)}
            </div>
          </div>
        ))}

        {/* Major (day) label */}
        <div
          className="text-foreground/80 absolute left-0 text-xs font-medium"
          style={{ top: AXIS_Y + 24 }}
        >
          {formatDay(win.start)}
        </div>

        {/* Draggable cursor (custom time) */}
        {cursorVisible && (
          <div
            className="absolute top-0 z-10 flex w-4 cursor-ew-resize justify-center"
            style={{ left: cursorX - 8, height: AXIS_Y }}
            title={`${formatDay(currentTime)} · ${formatClock(currentTime, true)}`}
            onPointerDown={handleCursorPointerDown}
            onPointerMove={handleCursorPointerMove}
            onPointerUp={handleCursorPointerUp}
            onPointerCancel={handleCursorPointerUp}
          >
            <div className="h-full w-0.5 bg-sky-500" />
            <div className="absolute top-0.5 size-2.5 rounded-full border-2 border-white bg-sky-500 shadow dark:border-neutral-900" />
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

type UsePlaybackClockOptions = {
  /** Start of the timeline (epoch ms). */
  start: number;
  /** End of the timeline (epoch ms). */
  end: number;
  /** Playback rate as a multiple of real time (default: 100). */
  initialSpeed?: number;
  /** Restart from the beginning when the end is reached (default: true). */
  loop?: boolean;
};

export type PlaybackClock = {
  /** Current cursor position (epoch ms). */
  time: number;
  isPlaying: boolean;
  /** Playback rate as a multiple of real time. */
  speed: number;
  /** Progress through the timeline, 0–1. */
  progress: number;
  play: () => void;
  pause: () => void;
  toggle: () => void;
  /** Jump the cursor to an absolute time (clamped to the bounds). */
  seek: (time: number) => void;
  /** Jump to the start and play. */
  restart: () => void;
  setSpeed: (speed: number) => void;
};

const clamp = (value: number, min: number, max: number) =>
  Math.max(min, Math.min(max, value));

/**
 * A requestAnimationFrame-driven clock that advances a cursor across a time
 * range at a configurable multiple of real time — the React equivalent of
 * LeafletPlayback's Clock. The cursor is decoupled from frame rate by scaling
 * each frame's elapsed wall-clock time by `speed`.
 */
export function usePlaybackClock({
  start,
  end,
  initialSpeed = 100,
  loop = true,
}: UsePlaybackClockOptions): PlaybackClock {
  const [time, setTime] = useState(start);
  const [isPlaying, setIsPlaying] = useState(false);
  const [speed, setSpeed] = useState(initialSpeed);

  const timeRef = useRef(start);
  const speedRef = useRef(speed);
  const startRef = useRef(start);
  const endRef = useRef(end);
  const loopRef = useRef(loop);
  const rafRef = useRef<number | null>(null);
  const lastRef = useRef<number | null>(null);

  // Keep the animation-frame loop reading the latest props without restarting.
  useEffect(() => {
    speedRef.current = speed;
    startRef.current = start;
    endRef.current = end;
    loopRef.current = loop;
  });

  const commit = useCallback((next: number) => {
    timeRef.current = next;
    setTime(next);
  }, []);

  useEffect(() => {
    if (!isPlaying) return;

    const frame = (now: number) => {
      if (lastRef.current === null) lastRef.current = now;
      const dt = now - lastRef.current;
      lastRef.current = now;

      let next = timeRef.current + dt * speedRef.current;
      if (next >= endRef.current) {
        if (loopRef.current) {
          next = startRef.current;
        } else {
          commit(endRef.current);
          setIsPlaying(false);
          return;
        }
      }
      commit(next);
      rafRef.current = requestAnimationFrame(frame);
    };

    rafRef.current = requestAnimationFrame(frame);
    return () => {
      if (rafRef.current !== null) cancelAnimationFrame(rafRef.current);
      rafRef.current = null;
      lastRef.current = null;
    };
  }, [isPlaying, commit]);

  const seek = useCallback(
    (next: number) => {
      commit(clamp(next, startRef.current, endRef.current));
    },
    [commit],
  );

  const play = useCallback(() => {
    // Pressing play at the very end rewinds first, so it never no-ops.
    if (timeRef.current >= endRef.current - 1) commit(startRef.current);
    setIsPlaying(true);
  }, [commit]);

  const pause = useCallback(() => setIsPlaying(false), []);

  const toggle = useCallback(() => {
    if (isPlaying) {
      setIsPlaying(false);
    } else {
      play();
    }
  }, [isPlaying, play]);

  const restart = useCallback(() => {
    commit(startRef.current);
    setIsPlaying(true);
  }, [commit]);

  const span = end - start;
  const progress = span > 0 ? clamp((time - start) / span, 0, 1) : 0;

  return {
    time,
    isPlaying,
    speed,
    progress,
    play,
    pause,
    toggle,
    seek,
    restart,
    setSpeed,
  };
}
